import React from 'react'
import './modal.css'

const Modal = (props) => {
  return (
    <div className='modal-backdrop'>
      <div className='modal'>
        {props.children}

        <h1>Modal</h1>
        <p>{props.title}</p>
        <button onClick={props.back}>go back</button>
      </div>
    </div>
  )
}

export default Modal
